export function getGeneratedAnimationFramePack(id: string | undefined): GeneratedAnimationFramePack | undefined {
  if (!id) return undefined;
  return GENERATED_ANIMATION_FRAME_PACKS[id as GeneratedAnimationClipId];
}

export function decodeGeneratedAnimationFrame(clipId: string | undefined, frameIndex: number): Uint32Array | undefined {
  const pack = getGeneratedAnimationFramePack(clipId);
  if (!pack || frameIndex < 0 || frameIndex >= pack.frames.length) return undefined;
  const frame = pack.frames[frameIndex];
  const out = new Uint32Array(pack.width * pack.height);
  let cursor = 0;
  for (let i = 0; i < frame.rle.length; i += 2) {
    const count = frame.rle[i] | 0;
    const value = frame.rle[i + 1] >>> 0;
    out.fill(value, cursor, cursor + count);
    cursor += count;
  }
  return cursor === out.length ? out : undefined;
}
